issue_body:
Hello
I have a problem I can't figure out what is wrong. I am trying to write a small rule engine modeling loan request process for my university. The first and second state are responsible for filling some form. 

The problem is it works well once when I change the context variable to which I post the answers (like c.s. to c.state). When I start script for the second time it skips some questions and launches 'all_asked(c)' method even though not all questions are asked. Could you please help me and tell me what is wrong with my code?

```
from durable.lang import *
import sys
import os
from random import randint

sid=randint(1,10000000)

with statechart('chart1'):
    with state('Init form'):
        @to('Fill form')
        @when_all(pri(1),m.subject == 'start_application')
        def init_q(c):
            c.s.q1asked='false'
            c.s.q2asked='false'
            c.s.q3asked='false'
            c.s.q4asked='false'
            c.s.q5asked='false'
            c.s.q6asked='false'
            c.s.id=2
            print('Questions initialized')
            
    with state('Fill form'):   
	
        @to('Fill form')
        @when_all(c.s.q1asked=='false')
        def q1(c):
            name = raw_input('Name and surname: ')
            c.post('chart1', {'id': c.s.id, 'sid': sid, 'name': name})
            c.s.q1asked='true'
            c.s.id+=1
            
        @to('Fill form')
        @when_all(c.s.q2asked=='false')
        def q2(c):
            age = int(input('Age: '))
            c.post('chart1', {'id': c.s.id, 'sid': sid, 'age': age})
            c.s.q2asked='true'
            c.s.id+=1

        @to('Fill form')
        @when_all(c.s.q3asked=='false')
        def q3(c):
            income = int(input('Income: '))
            c.post('chart1', {'id': c.s.id, 'sid': sid, 'income': income})
            c.s.q3asked='true'
            c.s.id+=1
            
        @to('Fill form')
        @when_all(c.s.q4asked=='false')
        def q4(c):
            loan = int(input('Loan ammount: '))
            c.post('chart1', {'id': c.s.id, 'sid': sid, 'loan': loan})
            c.s.q4asked='true'
            c.s.id+=1
    
        @to('Fill form')
        @when_all(c.s.q5asked=='false')
        def q5(c):
            expenses = int(input('Average expenses: '))
            c.post('chart1', {'id': c.s.id, 'sid': sid, 'expenses': expenses})
            c.s.q5asked='true'
            c.s.id+=1
            
        @to('Fill form')
        @when_all(c.s.q6asked=='false')
        def q6(c):
            time = int(input('Payback time: '))
            c.post('chart1', {'id': c.s.id, 'sid': sid, 'time': time})
            c.s.q6asked='true'
            c.s.id+=1
            
        @to('Initial form checking')
        @when_all(c.s.q1asked=='true', c.s.q2asked=='true', c.s.q3asked=='true', c.s.q4asked=='true', c.s.q5asked=='true', c.s.q6asked=='true')
        def all_asked(c):
            print ('Passed to initial form checking')
    
    with state('Initial form checking'):    
        @to('denied')
        @when_all(pri(1),c.age << m.age < 18)
        def denied_age(c):
            print ('Loan denied due to age: {0}'.format(c.age.age))

        @to('denied')
        @when_all(pri(1),m.income < 0)
        def denied_incomes(c):
            print ('Loan denied due to zero income')
		
        @to('denied')
        @when_all(pri(1),c.income << m.income > 0, 
		                 c.income.income < m.expenses)
        def denied_expenses(c):
            print ('Loan denied due to expenses {0} higher than income {1}'.format(c.expenses.expenses,c.income.income))
			
        #@to('denied')
        #@when_all(pri(1),c.loan << m.loan > 0, c.time << m.time > 0, c.income << m.income > 0, c.expenses << m.expenses > 0, c.loan.loan / c.time.time > c.income.income - c.expenses.expenses)
        #def denied_rate(c):
        #    print ('Loan denied due to rate higher than spare money')
            
        @to('approved')
        @when_all(1 >= 0, c.loan << m.loan > 0, c.time << m.time > 0, c.income << m.income > 0)
        def accepted(c):
            print ('Loan for {0}, aged {1}, for {2} in {3} rates'.format(c.name.name,c.age.age,c.loan.loan,c.time.time))
            print ('Initial loan checking approved')
            

    state('denied')
    state('approved')
    
    @when_start
    def start(host):
        host.post('chart1', {'id': 1, 'sid': sid, 'subject': 'start_application'})

run_all()
```

